"use client";
/* waypoint-world-whitsundays.html
   Generated from the frozen v1.0 design build — markup, styles and behaviour
   are preserved exactly. Edit content in the CMS or in the source HTML under
   /design-source, then re-run scripts/convert.py. */
import { useEffect } from "react";

const CSS = "\n/* ============================================================\n   WAYPOINT & Co. \u2014 THE WORLD\n   Phase Eight \u00b7 Master Destination Template\n   World 01 \u00b7 The Whitsundays\n   Motion: AIR vertical + SEA horizontal + STAY inward.\n   The destination is orbital \u2014 everything revolves around place.\n   ============================================================ */\n\n:root{\n  /* house */\n  --ivory:      #F1EEE7;\n  --charcoal:   #211F1B;\n  --metal:      #B3B0A7;\n  --ink-soft:   #6D6A61;\n  --ink-on-dark:#EDEAE1;\n\n  /* the Whitsundays \u2014 limestone, turquoise, white sand, morning haze, salt, sun */\n  --haze:       #E9EBE6;\n  --salt:       #EFEDE4;\n  --sand:       #EDE6D6;\n  --limestone:  #DCD4C3;\n  --water-pale: #C2D5D0;\n  --water:      #8FB3AE;\n  --water-deep: #5E8A86;\n  --sea-ink:    #3E5F5C;\n  --sun:        #C8A97E;\n\n  --serif: \"Instrument Serif\", Georgia, serif;\n  --sans:  \"Instrument Sans\", -apple-system, \"Helvetica Neue\", sans-serif;\n  --mono:  \"IBM Plex Mono\", \"SF Mono\", monospace;\n\n  --gutter: clamp(20px, 5vw, 72px);\n  --max: 1360px;\n  --ease: cubic-bezier(0.22, 1, 0.36, 1);\n}\n\n*{ margin:0; padding:0; box-sizing:border-box; }\nhtml{ scroll-behavior:smooth; }\nbody{\n  background: var(--salt);\n  color: var(--charcoal);\n  font-family: var(--sans);\n  font-size: 16px;\n  line-height: 1.68;\n  -webkit-font-smoothing: antialiased;\n  overflow-x: hidden;\n}\n::selection{ background: var(--water-deep); color: var(--salt); }\na{ color: inherit; text-decoration: none; }\nbutton{ font: inherit; color: inherit; background: none; border: none; cursor: pointer; }\n\n.wrap{ max-width: var(--max); margin: 0 auto; padding-left: var(--gutter); padding-right: var(--gutter); }\n\n.eyebrow{\n  font-family: var(--mono); font-size: 11px; font-weight: 400;\n  letter-spacing: 0.32em; text-transform: uppercase; color: var(--water-deep);\n}\n.dark .eyebrow{ color: var(--water); }\n\n.display{ font-family: var(--serif); font-weight: 400; line-height: 1.07; letter-spacing: -0.01em; }\n\n.lede{ font-size: clamp(17px, 1.35vw, 20px); line-height: 1.78; color: var(--ink-soft); max-width: 56ch; }\n.dark .lede{ color: #BDC4BD; }\n\n.mono-note{\n  font-family: var(--mono); font-size: 11.5px; font-weight: 300;\n  letter-spacing: .08em; line-height: 1.9; color: var(--ink-soft);\n}\n.dark .mono-note{ color: #93A09B; }\n\n.action{\n  display: inline-flex; align-items: center; gap: 14px;\n  font-size: 13px; font-weight: 500;\n  letter-spacing: .18em; text-transform: uppercase;\n  padding: 17px 30px;\n  border: 1px solid var(--charcoal);\n  transition: background .5s var(--ease), color .5s var(--ease);\n}\n.action .mark{ font-family: var(--mono); font-weight: 300; transition: transform .5s var(--ease); }\n.action:hover{ background: var(--charcoal); color: var(--salt); }\n.action:hover .mark{ transform: translateX(4px); }\n.action.solid{ background: var(--charcoal); color: var(--salt); }\n.action.solid:hover{ background: var(--sea-ink); border-color: var(--sea-ink); }\n.action.quiet{ border: none; padding: 6px 0; border-bottom: 1px solid var(--metal); }\n.action.quiet:hover{ background: none; color: var(--water-deep); border-bottom-color: var(--water-deep); }\n.dark .action{ border-color: var(--ink-on-dark); color: var(--ink-on-dark); }\n.dark .action:hover{ background: var(--ink-on-dark); color: var(--charcoal); }\n\na:focus-visible, button:focus-visible{ outline: 2px solid var(--water-deep); outline-offset: 4px; }\n\n/* ---------- the three movement languages ---------- */\n/* AIR \u2014 vertical rise */\n.rise{ opacity: 0; transform: translateY(30px); transition: opacity 1s var(--ease), transform 1.15s var(--ease); }\n.rise.in{ opacity: 1; transform: none; }\n/* SEA \u2014 horizontal drift */\n.drift{ opacity: 0; transform: translateX(-36px); transition: opacity 1.05s var(--ease), transform 1.25s var(--ease); }\n.drift.right{ transform: translateX(36px); }\n.drift.in{ opacity: 1; transform: none; }\n/* STAY \u2014 inward threshold */\n.enter{\n  opacity: 0; transform: scale(1.025); clip-path: inset(5% 7% 5% 7%);\n  transition: opacity 1.1s var(--ease), transform 1.4s var(--ease), clip-path 1.4s var(--ease);\n}\n.enter.in{ opacity: 1; transform: scale(1); clip-path: inset(0); }\n.d1{ transition-delay: .14s; } .d2{ transition-delay: .28s; } .d3{ transition-delay: .42s; }\n\n/* ============================================================\n   NAV\n   ============================================================ */\n.nav{\n  position: fixed; top: 0; left: 0; right: 0; z-index: 60;\n  display: flex; align-items: center; justify-content: space-between;\n  padding: 22px var(--gutter);\n  transition: background .5s var(--ease), box-shadow .5s var(--ease), padding .5s var(--ease);\n}\n.nav.scrolled{\n  background: rgba(239,237,228,0.93);\n  backdrop-filter: blur(12px);\n  padding-top: 14px; padding-bottom: 14px;\n  box-shadow: 0 1px 0 rgba(33,31,27,0.08);\n}\n.nav .wordmark{ font-family: var(--serif); font-size: 19px; letter-spacing: .04em; }\n.nav .wordmark span{ font-family: var(--mono); font-size: 10px; letter-spacing: .3em; color: var(--water-deep); display:block; margin-top: 1px; }\n.nav-links{ display: flex; gap: 34px; align-items: center; }\n.nav-links a{\n  font-family: var(--mono); font-size: 11px; letter-spacing: .28em; text-transform: uppercase;\n  color: var(--ink-soft); padding-bottom: 3px; border-bottom: 1px solid transparent;\n  transition: color .3s, border-color .3s;\n}\n.nav-links a:hover{ color: var(--charcoal); }\n.nav-links a.current{ color: var(--charcoal); border-bottom-color: var(--charcoal); }\n.nav-begin{\n  font-family: var(--mono); font-size: 11px; letter-spacing: .24em; text-transform: uppercase;\n  border: 1px solid var(--charcoal); padding: 10px 20px;\n  transition: background .4s var(--ease), color .4s var(--ease);\n}\n.nav-begin:hover{ background: var(--charcoal); color: var(--salt); }\n.nav.on-scene:not(.scrolled){ color: var(--charcoal); }\n\n/* ============================================================\n   1 \u00b7 ARRIVAL \u2014 first light, just water\n   ============================================================ */\n.hero{\n  position: relative; min-height: 100svh;\n  display: flex; flex-direction: column; justify-content: flex-end;\n  overflow: hidden;\n  background:\n    linear-gradient(180deg,\n      #E9EBE6 0%,      /* morning haze */\n      #DDE4DD 26%,\n      #C2D5D0 44%,     /* pale water meets sky */\n      #8FB3AE 58%,\n      #79A19C 72%,\n      #C9CDBE 88%,     /* shallows over sand */\n      #EDE6D6 100%);   /* white sand */\n}\n/* slow discovery \u2014 the scene breathes rather than moves */\n.hero .scene{\n  position: absolute; inset: -4%;\n  background:\n    radial-gradient(120% 40% at 30% 46%, rgba(233,235,230,0.35), transparent 66%),\n    radial-gradient(140% 34% at 74% 58%, rgba(143,179,174,0.25), transparent 70%),\n    radial-gradient(100% 28% at 50% 88%, rgba(237,230,214,0.5), transparent 74%);\n  animation: discover 60s var(--ease) infinite alternate;\n}\n@keyframes discover{\n  from{ transform: scale(1) translateX(-1.2%); }\n  to{   transform: scale(1.045) translateX(1.2%); }\n}\n/* the line begins \u2014 faint, patient */\n.hero-line{\n  position: absolute; left: 50%; top: 34%; bottom: 0; width: 1px;\n  transform: translateX(-.5px);\n  background: linear-gradient(180deg, transparent, rgba(62,95,92,0.35) 70%, rgba(62,95,92,0.55) 100%);\n}\n.hero-line::after{\n  content:\"\"; position: absolute; bottom: 10vh; left: 50%; transform: translateX(-50%);\n  width: 7px; height: 7px; border-radius: 50%;\n  border: 1px solid rgba(62,95,92,0.7);\n}\n.hero-inner{ position: relative; z-index: 2; padding-bottom: clamp(60px, 9vh, 110px); }\n.hero h1{\n  font-size: clamp(42px, 6.6vw, 96px);\n  max-width: 15ch;\n}\n.hero .lede{ color: rgba(33,31,27,0.72); margin-top: 24px; max-width: 44ch; }\n.hero-actions{ display: flex; gap: 18px; margin-top: 42px; flex-wrap: wrap; }\n.hero-ident{\n  position: absolute; right: var(--gutter); bottom: clamp(60px, 9vh, 110px);\n  text-align: right; z-index: 2;\n  font-family: var(--mono); font-size: 11px; font-weight: 300;\n  letter-spacing: .3em; line-height: 2.3; color: rgba(62,95,92,0.75);\n}\n.hero-ident b{ font-weight: 400; color: var(--sea-ink); letter-spacing: .34em; }\n.hero .load{ opacity: 0; transform: translateY(24px); animation: settle-in 1.6s var(--ease) forwards; }\n.hero .load.l2{ animation-delay: .35s; }\n.hero .load.l3{ animation-delay: .65s; }\n.hero .load.l4{ animation-delay: .95s; }\n@keyframes settle-in{ to{ opacity: 1; transform: none; } }\n\n/* ============================================================\n   2 \u00b7 SENSE OF PLACE \u2014 immerse, don't explain\n   ============================================================ */\n.sense{ padding: clamp(96px, 14vh, 180px) 0; }\n.sense-head{ max-width: 620px; margin-bottom: clamp(56px, 8vh, 96px); }\n.sense-head h2{ font-size: clamp(30px, 3.4vw, 48px); margin-top: 20px; }\n.observations{\n  display: grid; grid-template-columns: repeat(12, 1fr);\n  gap: clamp(16px, 2vw, 28px);\n}\n.obs{ position: relative; overflow: hidden; }\n.obs .frame{ position: relative; width: 100%; }\n.obs .frame::after{\n  content:\"\"; position:absolute; inset: 12px;\n  border: 1px solid rgba(239,237,228,0.5); pointer-events: none;\n}\n.obs .shot{\n  position: absolute; left: 20px; top: 18px;\n  font-family: var(--mono); font-size: 9.5px; font-weight: 300;\n  letter-spacing: .26em; text-transform: uppercase; color: rgba(239,237,228,0.85);\n}\n.obs figcaption{\n  display: flex; justify-content: space-between; align-items: baseline; gap: 16px;\n  padding-top: 14px;\n}\n.obs .word{ font-family: var(--serif); font-style: italic; font-size: clamp(18px, 1.6vw, 23px); }\n.obs .note{ font-family: var(--mono); font-size: 10px; font-weight: 300; letter-spacing: .18em; text-transform: uppercase; color: var(--ink-soft); text-align: right; }\n/* mosaic placement + tonal placeholder frames (commissioned photography) */\n.obs.o1{ grid-column: 1 / span 7; }  .obs.o1 .frame{ aspect-ratio: 16/10;\n  background: linear-gradient(170deg, #DDE4DD 0%, #C2D5D0 46%, #8FB3AE 100%); }\n.obs.o2{ grid-column: 8 / span 5; margin-top: clamp(40px, 6vh, 80px); } .obs.o2 .frame{ aspect-ratio: 4/5;\n  background: linear-gradient(180deg, #EDE6D6 0%, #DCD4C3 58%, #C8A97E 120%); }\n.obs.o3{ grid-column: 1 / span 4; margin-top: clamp(-30px, -3vh, -12px); } .obs.o3 .frame{ aspect-ratio: 4/5;\n  background: linear-gradient(195deg, #E9EBE6 0%, #C2D5D0 70%, #9FBDB7 100%); }\n.obs.o4{ grid-column: 5 / span 8; margin-top: clamp(28px, 4vh, 56px); } .obs.o4 .frame{ aspect-ratio: 16/9;\n  background: linear-gradient(160deg, #79A19C 0%, #8FB3AE 40%, #DCE3DA 100%); }\n.obs.o5{ grid-column: 2 / span 5; margin-top: clamp(28px, 4vh, 56px); } .obs.o5 .frame{ aspect-ratio: 1/1;\n  background: linear-gradient(180deg, #EFEDE4 0%, #EDE6D6 60%, #DCD4C3 100%); }\n.obs.o6{ grid-column: 8 / span 5; margin-top: clamp(60px, 8vh, 110px); } .obs.o6 .frame{ aspect-ratio: 4/3;\n  background: linear-gradient(200deg, #E9EBE6 0%, #DDE4DD 44%, #B9CFC9 100%); }\n\n/* ============================================================\n   3 \u00b7 THE JOURNEY \u2014 the geographic descent\n   ============================================================ */\n\n/* ---- WJ: geographic journey spine (v2.0.1) ---- */\n.wj{ background: var(--haze); padding: clamp(80px,12vh,150px) 0; }\n.wj-grid{ display:grid; grid-template-columns: minmax(220px,26%) minmax(0,1fr); gap: clamp(30px,4vw,72px); max-width:1360px; margin:0 auto; padding:0 clamp(20px,5vw,72px); align-items:start; }\n.wj-rail{ position:sticky; top: clamp(48px,10vh,110px); align-self:start; }\n.wj-brand{ font-family: var(--mono); font-size:10px; letter-spacing:.42em; color: var(--sea-ink); }\n.wj-course{ font-family: var(--mono); font-size:9px; letter-spacing:.26em; color: var(--sea-ink); opacity:.65; margin-top:6px; }\n.wj-rail-inner{ position:relative; padding-left:18px; }\n.wj-line{ position:absolute; left:3px; top:64px; bottom:34px; width:1px; background: var(--sea-ink); opacity:.28; }\n.wj-marks{ list-style:none; margin:34px 0 0; padding:0; display:flex; flex-direction:column; gap: clamp(26px,4vh,44px); }\n.wj-mark{ position:relative; opacity:.42; transition: opacity .6s cubic-bezier(.22,1,.36,1); }\n.wj-mark .d{ position:absolute; left:-18.5px; top:5px; width:6px; height:6px; border:1px solid var(--sea-ink); transform:rotate(45deg); background:transparent; transition: background .5s; }\n.wj-mark .n{ font-family: var(--mono); font-size:9px; letter-spacing:.3em; color: var(--sea-ink); display:block; }\n.wj-mark .p{ font-family: var(--serif); font-size:17px; color: var(--sea-ink); display:block; margin-top:3px; line-height:1.2; }\n.wj-mark .c{ font-family: var(--mono); font-size:8.5px; letter-spacing:.18em; color: var(--sea-ink); opacity:.6; display:block; margin-top:4px; }\n.wj-mark.on{ opacity:1; }\n.wj-mark.on .d{ background: var(--sea-ink); }\n.wj-progress{ font-family: var(--mono); font-size:9px; letter-spacing:.3em; color: var(--sea-ink); opacity:.6; margin-top:34px; }\n.wj-stages{ display:flex; flex-direction:column; gap: clamp(70px,11vh,130px); }\n.wj-shead{ display:flex; justify-content:space-between; gap:16px; font-family: var(--mono); font-size:9.5px; letter-spacing:.26em; color: var(--sea-ink); opacity:.75; border-top:1px solid rgba(62,95,92,.3); padding-top:14px; }\n.wj-sname{ font-family: var(--serif); font-weight:400; font-size: clamp(28px,3.2vw,44px); color: var(--sea-ink); margin:14px 0 4px; line-height:1.08; }\n.wj-srole{ font-family: var(--serif); font-style:italic; font-size:17px; color: var(--sea-ink); opacity:.72; margin:0 0 20px; }\n.wj-frame{ position:relative; aspect-ratio:16/9; margin:0 0 20px; }\n.wj-frame::after{ content:\"\"; position:absolute; inset:12px; border:1px solid rgba(244,239,226,.55); pointer-events:none; }\n.wj-scopy{ font-family: var(--sans); font-size:16px; line-height:1.75; color: var(--sea-ink); max-width:56ch; margin:0 0 18px; }\n.wj-sact .action{ font-size:12px; }\n@media (max-width:860px){\n  .wj-grid{ grid-template-columns:1fr; }\n  .wj-rail{ position:static; }\n  .wj-rail-inner{ padding-left:0; }\n  .wj-line{ display:none; }\n  .wj-marks{ flex-direction:row; overflow-x:auto; gap:22px; margin-top:22px; padding-bottom:8px; scrollbar-width:none; border-bottom:1px solid rgba(62,95,92,.28); }\n  .wj-marks::-webkit-scrollbar{ display:none; }\n  .wj-mark{ min-width:150px; }\n  .wj-mark .d{ display:none; }\n  .wj-stages{ margin-top:34px; }\n}\n@media (prefers-reduced-motion:reduce){ .wj-mark{ transition:none; } }\n\n.descent{ background: var(--haze); padding: clamp(96px, 14vh, 180px) 0; }\n.descent-head{ text-align: center; max-width: 640px; margin: 0 auto clamp(64px, 9vh, 120px); }\n.descent-head h2{ font-size: clamp(32px, 3.8vw, 54px); margin-top: 20px; }\n.chart{ position: relative; max-width: 680px; margin: 0 auto; }\n.chart-line{\n  position: absolute; left: 50%; top: 8px; bottom: 8px; width: 1px;\n  transform: translateX(-.5px); background: var(--metal);\n}\n.chart-line .plotted{\n  position: absolute; top: 0; left: 0; width: 100%; height: 0%;\n  background: var(--sea-ink); transition: height .2s linear;\n}\n.wpt{\n  position: relative; text-align: center;\n  padding: 0 0 clamp(56px, 7.5vh, 92px);\n}\n.wpt:last-child{ padding-bottom: 0; }\n.wpt .node{\n  width: 9px; height: 9px; border-radius: 50%;\n  border: 1px solid var(--sea-ink); background: var(--haze);\n  margin: 0 auto 20px; position: relative; z-index: 2;\n  transition: background .5s var(--ease);\n}\n.wpt.in .node{ background: var(--sea-ink); }\n.wpt .w-scale{\n  font-family: var(--mono); font-size: 10.5px; letter-spacing: .34em;\n  text-transform: uppercase; color: var(--water-deep); margin-bottom: 10px;\n}\n.wpt .w-name{ font-family: var(--serif); font-size: clamp(26px, 3vw, 40px); line-height: 1.12; }\n.wpt .w-fix{ margin-top: 8px; }\n.wpt .w-story{\n  margin: 16px auto 0; max-width: 44ch;\n  font-size: 15px; color: var(--ink-soft); line-height: 1.75;\n}\n.wpt.scale-shift .w-name{ font-style: italic; color: var(--water-deep); }\n\n/* ============================================================\n   4/5/6 \u00b7 ARRIVE \u2014 BELONG \u2014 EXPLORE  (children of the world)\n   ============================================================ */\n.pillar{ position: relative; overflow: hidden; }\n.pillar .wrap{ position: relative; }\n.pillar-grid{\n  display: grid; grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);\n  gap: clamp(40px, 6vw, 110px); align-items: center;\n  padding: clamp(96px, 14vh, 180px) 0;\n}\n.pillar h2{ font-size: clamp(34px, 4.2vw, 60px); margin: 20px 0 26px; max-width: 14ch; }\n.pillar .p-themes{\n  margin-top: 26px;\n  font-family: var(--mono); font-size: 11px; font-weight: 300;\n  letter-spacing: .14em; text-transform: uppercase; color: var(--ink-soft);\n  display: flex; flex-wrap: wrap; gap: 8px 0; max-width: 46ch;\n}\n.pillar .p-themes span::after{ content:\"\u00b7\"; margin: 0 10px; color: var(--metal); }\n.pillar .p-themes span:last-child::after{ content:\"\"; margin: 0; }\n.pillar .action{ margin-top: 36px; }\n.pillar .scene-frame{ position: relative; overflow: hidden; }\n.pillar .scene-frame::after{\n  content:\"\"; position:absolute; inset: 14px;\n  border: 1px solid rgba(239,237,228,0.55); pointer-events: none;\n}\n.pillar .scene-frame .s-note{\n  position: absolute; left: 26px; bottom: 22px;\n  font-family: var(--mono); font-size: 10px; letter-spacing: .3em;\n  text-transform: uppercase; color: rgba(239,237,228,0.85);\n}\n/* ARRIVE \u2014 vertical, atmospheric */\n.pillar.arrive{ background: var(--salt); }\n.pillar.arrive .scene-frame{ aspect-ratio: 4/5;\n  background: linear-gradient(180deg, #55606A 0%, #8D9598 34%, #C4CDC4 62%, #C2D5D0 100%);\n}\n/* BELONG \u2014 inward, grounded */\n.pillar.belong{ background: var(--sand); }\n.pillar.belong .scene-frame{ aspect-ratio: 4/5;\n  background: linear-gradient(165deg, #DCD4C3 0%, #EDE6D6 40%, #8FB3AE 110%);\n}\n.pillar.belong .pillar-grid > .scene-holder{ order: -1; }\n/* EXPLORE \u2014 horizontal, tidal */\n.pillar.explore{ background: var(--haze); }\n.pillar.explore .scene-frame{ aspect-ratio: 16/10;\n  background: linear-gradient(90deg, #5E8A86 0%, #8FB3AE 44%, #C2D5D0 78%, #EDE6D6 100%);\n}\n.pillar.explore .pillar-grid{ grid-template-columns: minmax(0, 0.9fr) minmax(0, 1.1fr); }\n\n/* ============================================================\n   7 \u00b7 EXTRAORDINARY MOMENTS \u2014 stories, not lists\n   ============================================================ */\n.moments{ background: var(--charcoal); color: var(--ink-on-dark); padding: clamp(104px, 15vh, 190px) 0; position: relative; overflow: hidden; }\n.moments::before{\n  content:\"\"; position: absolute; inset: 0; pointer-events: none;\n  background:\n    radial-gradient(80% 55% at 85% 0%, rgba(143,179,174,0.10), transparent 62%),\n    radial-gradient(70% 45% at 8% 100%, rgba(200,169,126,0.08), transparent 58%);\n}\n.moments .wrap{ position: relative; }\n.moments h2{ font-size: clamp(34px, 4.4vw, 64px); margin: 22px 0 26px; max-width: 15ch; }\n.moment-flow{ margin-top: clamp(56px, 7vh, 90px); }\n.mstory{\n  display: grid; grid-template-columns: 200px minmax(0, 1fr) auto;\n  gap: clamp(24px, 4vw, 64px); align-items: baseline;\n  padding: clamp(24px, 3vh, 36px) 0;\n  border-top: 1px solid rgba(179,176,167,0.22);\n  transition: padding-left .6s var(--ease);\n}\n.mstory:last-child{ border-bottom: 1px solid rgba(179,176,167,0.22); }\n.mstory:hover{ padding-left: 14px; }\n.mstory .m-name{\n  font-family: var(--mono); font-size: 11px; letter-spacing: .3em;\n  text-transform: uppercase; color: var(--water);\n}\n.mstory .m-line{ font-family: var(--serif); font-size: clamp(19px, 1.9vw, 26px); line-height: 1.35; max-width: 30ch; }\n.mstory .m-go{\n  font-family: var(--mono); font-size: 10.5px; letter-spacing: .24em; text-transform: uppercase;\n  color: #93A09B; border-bottom: 1px solid rgba(147,160,155,0.4);\n  padding-bottom: 3px; transition: color .3s, border-color .3s;\n  white-space: nowrap;\n}\n.mstory .m-go:hover{ color: var(--ink-on-dark); border-color: var(--ink-on-dark); }\n\n/* ============================================================\n   8 \u00b7 THE JOURNAL\n   ============================================================ */\n.journal{ padding: clamp(96px, 14vh, 180px) 0; background: var(--salt); }\n.journal-head{ max-width: 700px; margin-bottom: clamp(56px, 8vh, 96px); }\n.journal-head h2{ font-size: clamp(34px, 4.2vw, 60px); margin-top: 20px; }\n.stories{\n  display: grid; grid-template-columns: repeat(12, 1fr);\n  gap: clamp(16px, 2vw, 28px);\n}\n.story{ position: relative; }\n.story .frame{ position: relative; overflow: hidden; }\n.story .frame::after{\n  content:\"\"; position: absolute; inset: 12px;\n  border: 1px solid rgba(239,237,228,0.5); pointer-events: none;\n}\n.story .frame .sc{\n  position: absolute; left: 20px; top: 18px;\n  font-family: var(--mono); font-size: 9.5px; font-weight: 300;\n  letter-spacing: .26em; text-transform: uppercase; color: rgba(239,237,228,0.85);\n}\n.story h3{\n  font-family: var(--serif); font-weight: 400;\n  font-size: clamp(20px, 1.9vw, 27px); line-height: 1.22;\n  margin-top: 16px; max-width: 22ch;\n}\n.story .s-kind{ margin-top: 8px; }\n.story.s1{ grid-column: 1 / span 5; } .story.s1 .frame{ aspect-ratio: 4/5;\n  background: linear-gradient(180deg, #EDE6D6 0%, #C2D5D0 56%, #8FB3AE 100%); }\n.story.s2{ grid-column: 6 / span 7; } .story.s2 .frame{ aspect-ratio: 16/10;\n  background: linear-gradient(170deg, #DDE4DD 0%, #9FBDB7 60%, #5E8A86 100%); }\n.story.s3{ grid-column: 1 / span 7; margin-top: clamp(32px, 4vh, 56px); } .story.s3 .frame{ aspect-ratio: 16/10;\n  background: linear-gradient(200deg, #E9EBE6 0%, #C2D5D0 48%, #79A19C 100%); }\n.story.s4{ grid-column: 8 / span 5; margin-top: clamp(56px, 8vh, 96px); } .story.s4 .frame{ aspect-ratio: 4/5;\n  background: linear-gradient(180deg, #DCD4C3 0%, #EDE6D6 54%, #C8A97E 130%); }\n.story.s5{ grid-column: 4 / span 6; margin-top: clamp(32px, 4vh, 56px); } .story.s5 .frame{ aspect-ratio: 16/9;\n  background: linear-gradient(90deg, #8FB3AE 0%, #C2D5D0 52%, #EFEDE4 100%); }\n\n/* ============================================================\n   9 \u00b7 ONE COMPLETE JOURNEY \u2014 continuous story\n   ============================================================ */\n.complete{ background: var(--haze); padding: clamp(96px, 14vh, 180px) 0; }\n.complete-head{ text-align: center; max-width: 640px; margin: 0 auto clamp(64px, 9vh, 110px); }\n.complete-head h2{ font-size: clamp(32px, 3.8vw, 54px); margin-top: 20px; }\n.voyage{ position: relative; max-width: 560px; margin: 0 auto; }\n.voyage-line{\n  position: absolute; left: 27px; top: 8px; bottom: 8px; width: 1px;\n  background: var(--metal);\n}\n.voyage-line .plotted{\n  position: absolute; top: 0; left: 0; width: 100%; height: 0%;\n  background: var(--sea-ink); transition: height .2s linear;\n}\n.leg{\n  position: relative;\n  display: grid; grid-template-columns: 56px minmax(0, 1fr);\n  gap: clamp(20px, 3vw, 40px); align-items: baseline;\n  padding: 0 0 clamp(38px, 5vh, 56px);\n}\n.leg:last-child{ padding-bottom: 0; }\n.leg .node{\n  width: 9px; height: 9px; border-radius: 50%;\n  border: 1px solid var(--sea-ink); background: var(--haze);\n  position: relative; z-index: 2; justify-self: center; top: 4px;\n  transition: background .5s var(--ease);\n}\n.leg.in .node{ background: var(--sea-ink); }\n.leg .l-kind{\n  font-family: var(--mono); font-size: 10px; letter-spacing: .3em;\n  text-transform: uppercase; color: var(--water-deep);\n}\n.leg .l-name{ font-family: var(--serif); font-size: clamp(21px, 2.2vw, 29px); line-height: 1.25; margin-top: 4px; }\n.leg .l-note{ font-size: 13.5px; color: var(--ink-soft); margin-top: 6px; max-width: 42ch; }\n.voyage-actions{ text-align: center; margin-top: clamp(52px, 7vh, 80px); display: flex; gap: 18px; justify-content: center; flex-wrap: wrap; }\n\n/* ============================================================\n   10 \u00b7 BEGIN \u2014 sunset; the line reaches its final waypoint\n   ============================================================ */\n.begin{\n  position: relative;\n  min-height: 88svh;\n  display: flex; align-items: center;\n  text-align: center;\n  color: var(--ink-on-dark);\n  overflow: hidden;\n  background:\n    linear-gradient(180deg,\n      #3E5F5C 0%,\n      #5E8A86 30%,\n      #8FA79A 52%,\n      #C8A97E 76%,\n      #DCC49C 90%,\n      #C9A87B 100%);\n}\n.begin::before{ /* the line completes */\n  content:\"\"; position: absolute; left: 50%; top: 0; height: 52%;\n  width: 1px; transform: translateX(-.5px);\n  background: linear-gradient(180deg, rgba(237,234,225,0.0), rgba(237,234,225,0.75));\n}\n.begin::after{ /* final waypoint */\n  content:\"\"; position: absolute; left: 50%; top: 52%; transform: translate(-50%, -50%);\n  width: 11px; height: 11px; border-radius: 50%;\n  border: 1px solid rgba(237,234,225,0.9);\n  background: rgba(237,234,225,0.25);\n}\n.begin .wrap{ position: relative; padding-top: 14vh; }\n.begin h2{ font-size: clamp(38px, 5.4vw, 84px); max-width: 14ch; margin: 0 auto 46px; text-shadow: 0 1px 26px rgba(33,31,27,0.18); }\n.begin .action.solid{ background: rgba(237,234,225,0.96); color: var(--charcoal); border-color: transparent; }\n.begin .action.solid:hover{ background: var(--salt); }\n\n/* ============================================================\n   FOOTER\n   ============================================================ */\n.footer{ background: var(--charcoal); color: var(--ink-on-dark); padding: clamp(64px, 8vh, 100px) 0 40px; }\n.footer-top{\n  display: grid; grid-template-columns: minmax(0,1.4fr) repeat(3, minmax(0,1fr));\n  gap: clamp(32px, 4vw, 64px);\n  padding-bottom: clamp(44px, 5vh, 64px);\n  border-bottom: 1px solid rgba(179,176,167,0.22);\n}\n.footer .wordmark{ font-family: var(--serif); font-size: 22px; }\n.footer .wordmark span{ font-family: var(--mono); font-size: 10px; letter-spacing: .3em; color: var(--water); display: block; margin-top: 4px; }\n.footer h4{ font-family: var(--mono); font-size: 10.5px; font-weight: 400; letter-spacing: .32em; text-transform: uppercase; color: var(--water); margin-bottom: 20px; }\n.footer ul{ list-style: none; display: flex; flex-direction: column; gap: 12px; }\n.footer ul a{ font-size: 14px; color: #BDC4BD; transition: color .3s; }\n.footer ul a:hover{ color: var(--ink-on-dark); }\n.footer-bottom{ display: flex; justify-content: space-between; gap: 24px; flex-wrap: wrap; padding-top: 32px; }\n.footer-bottom .mono-note{ color: #78847F; }\n\n/* ============================================================\n   REDUCED MOTION\n   ============================================================ */\n@media (prefers-reduced-motion: reduce){\n  html{ scroll-behavior: auto; }\n  *, *::before, *::after{ animation: none !important; transition: none !important; }\n  .rise, .drift, .enter, .hero .load{ opacity: 1; transform: none; clip-path: none; }\n  .chart-line .plotted, .voyage-line .plotted{ height: 100% !important; }\n}\n\n/* ============================================================\n   MOBILE \u2014 the world as a vertical log\n   ============================================================ */\n@media (max-width: 980px){\n  .observations{ display: flex; flex-direction: column; gap: 36px; }\n  .obs{ margin-top: 0 !important; }\n  .pillar-grid{ grid-template-columns: 1fr !important; }\n  .pillar.belong .pillar-grid > .scene-holder{ order: 0; }\n  .mstory{ grid-template-columns: 1fr; gap: 10px; }\n  .mstory .m-go{ justify-self: start; }\n  .stories{ display: flex; flex-direction: column; gap: 36px; }\n  .story{ margin-top: 0 !important; }\n  .footer-top{ grid-template-columns: 1fr 1fr; }\n  .hero-ident{ display: none; }\n  .nav-links{ display: none; }\n}\n@media (max-width: 560px){\n  .footer-top{ grid-template-columns: 1fr; }\n  .leg{ grid-template-columns: 40px minmax(0,1fr); }\n  .voyage-line{ left: 19px; }\n}\n";
const HTML = "<!-- ================================================================\n     THE WORLD \u00b7 MASTER DESTINATION TEMPLATE\n     World 01 \u00b7 The Whitsundays\n     data-cms=\"world\" \u2014 every child section queries the relationship\n     graph. No duplicated content: AIR, SEA, STAY, experiences,\n     journeys, journal entries and waypoints all render dynamically\n     from CMS-authored relationships for this destination.\n     ================================================================ -->\n\n<!-- ============ NAV ============ -->\n<nav class=\"nav on-scene\" id=\"nav\">\n  <a href=\"/\" class=\"wordmark\">WAYPOINT &amp; Co.<span>THE WORLD</span></a>\n  <div class=\"nav-links\">\n    <a href=\"/world\" class=\"current\" aria-current=\"page\">The World</a>\n    <a href=\"/sea\">Sea</a>\n    <a href=\"/stay\">Stay</a>\n    <a href=\"/air\">Air</a>\n  </div>\n  <a class=\"nav-begin\" href=\"/begin?dest=whitsundays&src=world-nav\">Begin</a>\n</nav>\n\n<!-- ============ 1 \u00b7 ARRIVAL \u2014 first light ============ -->\n<header class=\"hero\" id=\"arrival\" data-cms=\"world\" data-world=\"whitsundays\">\n  <div class=\"scene\" aria-hidden=\"true\"></div>\n  <div class=\"hero-line\" aria-hidden=\"true\"></div>\n\n  <div class=\"hero-inner wrap\">\n    <p class=\"eyebrow load\">The World \u00b7 01</p>\n    <h1 class=\"display load l2\">Some places are meant to be crossed slowly.</h1>\n    <p class=\"lede load l3\">The Whitsundays are experienced differently when every movement is considered.</p>\n    <div class=\"hero-actions load l4\">\n      <a class=\"action solid\" href=\"/begin?dest=whitsundays&src=world-hero\">Begin a journey <span class=\"mark\">\u2192</span></a>\n      <a class=\"action\" href=\"#descent\">Explore the passage <span class=\"mark\">\u2192</span></a>\n    </div>\n  </div>\n\n  <div class=\"hero-ident load l4\" aria-label=\"The World, number one: The Whitsundays\">\n    <b>THE WHITSUNDAYS</b><br>\n    20\u00b0S \u00b7 149\u00b0E<br>\n    SEVENTY-FOUR ISLANDS\n  </div>\n</header>\n\n<!-- ============ 2 \u00b7 SENSE OF PLACE ============ -->\n<section class=\"sense\" id=\"sense\">\n  <div class=\"wrap\">\n    <div class=\"sense-head\">\n      <p class=\"eyebrow rise\">Sense of place</p>\n      <h2 class=\"display rise d1\">Before the journey, the place itself.</h2>\n    </div>\n\n    <!-- Commissioned photography renders from mediaAsset \u00b7 placeholders carry shot briefs -->\n    <div class=\"observations\">\n      <figure class=\"obs o1 enter\">\n        <div class=\"frame\"><span class=\"shot\">SHOT \u00b7 OPEN WATER, FIRST LIGHT</span></div>\n        <figcaption><span class=\"word\">Wind.</span><span class=\"note\">From the south-east, most afternoons</span></figcaption>\n      </figure>\n      <figure class=\"obs o2 enter d1\">\n        <div class=\"frame\"><span class=\"shot\">SHOT \u00b7 SAND UNDERFOOT, NO HORIZON</span></div>\n        <figcaption><span class=\"word\">Sand.</span><span class=\"note\">Silica, cool at any hour</span></figcaption>\n      </figure>\n      <figure class=\"obs o3 drift\">\n        <div class=\"frame\"><span class=\"shot\">SHOT \u00b7 SURFACE TEXTURE, MID MORNING</span></div>\n        <figcaption><span class=\"word\">Water.</span><span class=\"note\">Clear to the seagrass</span></figcaption>\n      </figure>\n      <figure class=\"obs o4 drift right\">\n        <div class=\"frame\"><span class=\"shot\">SHOT \u00b7 CHANNEL BETWEEN ISLANDS</span></div>\n        <figcaption><span class=\"word\">Distance.</span><span class=\"note\">Islands measured in hours, not miles</span></figcaption>\n      </figure>\n      <figure class=\"obs o5 enter\">\n        <div class=\"frame\"><span class=\"shot\">SHOT \u00b7 HAZE OVER LIMESTONE</span></div>\n        <figcaption><span class=\"word\">Light.</span><span class=\"note\">Soft until ten, gold after four</span></figcaption>\n      </figure>\n      <figure class=\"obs o6 enter d1\">\n        <div class=\"frame\"><span class=\"shot\">SHOT \u00b7 ANCHORAGE BEFORE THE HOUSE WAKES</span></div>\n        <figcaption><span class=\"word\">Morning.</span><span class=\"note\">The passage at its quietest</span></figcaption>\n      </figure>\n    </div>\n  </div>\n</section>\n\n<!-- ============ 3 \u00b7 THE JOURNEY \u2014 geographic descent ============ -->\n<section class=\"wj\" id=\"descent\" aria-label=\"The course through the Whitsundays\">\n  <div class=\"wj-grid\">\n    <aside class=\"wj-rail\" aria-hidden=\"false\">\n      <div class=\"wj-rail-inner\">\n        <div class=\"wj-brand\">WAYPOINT</div>\n        <div class=\"wj-course\">COURSE 01 / WHITSUNDAYS \u00b7 20\u00b0 S</div>\n        <div class=\"wj-line\" aria-hidden=\"true\"></div>\n        <ol class=\"wj-marks\">\n          <li class=\"wj-mark\" data-wj=\"wj1\"><span class=\"d\"></span><span class=\"n\">01</span><span class=\"p\">Hamilton Island</span><span class=\"c\">20.3514\u00b0 S \u00b7 148.9519\u00b0 E</span></li>\n          <li class=\"wj-mark\" data-wj=\"wj2\"><span class=\"d\"></span><span class=\"n\">02</span><span class=\"p\">Whitehaven Beach</span><span class=\"c\">20.2820\u00b0 S \u00b7 149.0368\u00b0 E</span></li>\n          <li class=\"wj-mark\" data-wj=\"wj3\"><span class=\"d\"></span><span class=\"n\">03</span><span class=\"p\">Hook Island</span><span class=\"c\">20.1030\u00b0 S \u00b7 148.9220\u00b0 E</span></li>\n          <li class=\"wj-mark\" data-wj=\"wj4\"><span class=\"d\"></span><span class=\"n\">04</span><span class=\"p\">Hayman Island</span><span class=\"c\">20.0555\u00b0 S \u00b7 148.8858\u00b0 E</span></li>\n          <li class=\"wj-mark\" data-wj=\"wj5\"><span class=\"d\"></span><span class=\"n\">05</span><span class=\"p\">The Outer Reef</span><span class=\"c\">\u2248 19.7\u00b0 S \u00b7 OPEN WATER</span></li>\n        </ol>\n        <div class=\"wj-progress\"><span class=\"cur\">01</span> / 05</div>\n      </div>\n    </aside>\n    <div class=\"wj-stages\">\n      <article class=\"wj-stage\" id=\"wj1\" data-cms=\"place\" data-ref=\"hamilton-island\">\n        <header class=\"wj-shead\"><span class=\"wj-sn\">01 \u00b7 ARRIVE</span><span class=\"wj-sc\">20.3514\u00b0 S \u00b7 148.9519\u00b0 E</span></header>\n        <h3 class=\"wj-sname\">Hamilton Island</h3>\n        <p class=\"wj-srole\">Arrival and access.</p>\n        <div class=\"wj-frame\" style=\"background:linear-gradient(165deg,#8FB3AE 0%,#C2D5D0 52%,#EDE6D6 100%)\"></div>\n        <p class=\"wj-scopy\">The runway meets the water and the journey changes register. Private fixed-wing lands within sight of the marina; the residence, the vessel and the passage are minutes apart. Everything that follows starts here.</p>\n        <p class=\"wj-sact\"><a class=\"action\" href=\"/air/fleet\">Arrive by AIR <span class=\"mark\">\u2192</span></a></p>\n      </article>\n      <article class=\"wj-stage\" id=\"wj2\" data-cms=\"place\" data-ref=\"whitehaven\">\n        <header class=\"wj-shead\"><span class=\"wj-sn\">02 \u00b7 CROSS</span><span class=\"wj-sc\">20.2820\u00b0 S \u00b7 149.0368\u00b0 E</span></header>\n        <h3 class=\"wj-sname\">Whitehaven Beach</h3>\n        <p class=\"wj-srole\">The first crossing.</p>\n        <div class=\"wj-frame\" style=\"background:linear-gradient(165deg,#C2D5D0 0%,#EDE6D6 55%,#F4EFE2 100%)\"></div>\n        <p class=\"wj-scopy\">Seven kilometres of silica so fine it squeaks underfoot, best reached before the day arrives. The crossing from Hamilton is short; the change in register is complete.</p>\n        <p class=\"wj-sact\"><a class=\"action\" href=\"/sea/fleet\">Continue by SEA <span class=\"mark\">\u2192</span></a></p>\n      </article>\n      <article class=\"wj-stage\" id=\"wj3\" data-cms=\"place\" data-ref=\"hook-island\">\n        <header class=\"wj-shead\"><span class=\"wj-sn\">03 \u00b7 ANCHOR</span><span class=\"wj-sc\">20.1030\u00b0 S \u00b7 148.9220\u00b0 E</span></header>\n        <h3 class=\"wj-sname\">Hook Island</h3>\n        <p class=\"wj-srole\">Protected water and hidden anchorages.</p>\n        <div class=\"wj-frame\" style=\"background:linear-gradient(165deg,#3E5F5C 0%,#8FB3AE 55%,#C2D5D0 100%)\"></div>\n        <p class=\"wj-scopy\">The fjord-cut north of the group \u2014 still water inside Nara and Macona Inlets, coral gardens at the northern tips, and evenings where the only movement is tide. The anchorage is the destination.</p>\n        <p class=\"wj-sact\"><a class=\"action\" href=\"/begin?dest=whitsundays&src=world-course\" >Add to the journey <span class=\"mark\">\u2192</span></a></p>\n      </article>\n      <article class=\"wj-stage\" id=\"wj4\" data-cms=\"place\" data-ref=\"hayman-island\">\n        <header class=\"wj-shead\"><span class=\"wj-sn\">04 \u00b7 RETREAT</span><span class=\"wj-sc\">20.0555\u00b0 S \u00b7 148.8858\u00b0 E</span></header>\n        <h3 class=\"wj-sname\">Hayman Island</h3>\n        <p class=\"wj-srole\">A place to stay.</p>\n        <div class=\"wj-frame\" style=\"background:linear-gradient(165deg,#8FB3AE 0%,#B9CEC6 50%,#EDE6D6 100%)\"></div>\n        <p class=\"wj-scopy\">The most northerly of the group holds its own harbour and a quieter pace. From here the reef is close and the passage is behind you \u2014 a night ashore before the final horizon.</p>\n        <p class=\"wj-sact\"><a class=\"action\" href=\"/stay/collection\">View nearby stays <span class=\"mark\">\u2192</span></a></p>\n      </article>\n      <article class=\"wj-stage\" id=\"wj5\" data-cms=\"place\" data-ref=\"outer-reef\">\n        <header class=\"wj-shead\"><span class=\"wj-sn\">05 \u00b7 GO BEYOND</span><span class=\"wj-sc\">\u2248 19.7\u00b0 S \u00b7 OPEN WATER</span></header>\n        <h3 class=\"wj-sname\">The Outer Reef</h3>\n        <p class=\"wj-srole\">The final horizon.</p>\n        <div class=\"wj-frame\" style=\"background:linear-gradient(165deg,#2E4744 0%,#3E5F5C 45%,#8FB3AE 100%)\"></div>\n        <p class=\"wj-scopy\">When the weather opens, the passage gives way to a different scale of blue. Reef positions are chosen on the day, to conditions \u2014 which is exactly how it should be.</p>\n        <p class=\"wj-sact\"><a class=\"action\" href=\"/enquire?dest=whitsundays&src=world-course\">Request availability <span class=\"mark\">\u2192</span></a></p>\n      </article>\n    </div>\n  </div>\n</section>\n\n<!-- ============ 4 \u00b7 ARRIVE (AIR) \u2014 vertical ============ -->\n<section class=\"pillar arrive\" id=\"arrive\" data-cms=\"pillar\" data-pillar=\"air\" data-world=\"whitsundays\">\n  <div class=\"wrap pillar-grid\">\n    <div>\n      <p class=\"eyebrow rise\">Arrive</p>\n      <h2 class=\"display rise d1\">The world begins from the air.</h2>\n      <p class=\"lede rise d2\">Private fixed-wing to Hamilton Island or Proserpine; helicopter onward to the beach, the vessel or the residence. Arrival here is not a connection \u2014 it is the first view of the passage from above.</p>\n      <div class=\"p-themes rise d3\">\n        <span>Private aviation</span><span>Helicopter</span><span>Regional access</span><span>Coordinated arrival</span>\n      </div>\n      <a class=\"action rise d3\" href=\"/air?dest=whitsundays&src=world-arrive\">Continue into AIR <span class=\"mark\">\u2192</span></a>\n    </div>\n    <div class=\"scene-holder\">\n      <div class=\"scene-frame rise d1\" aria-hidden=\"true\">\n        <span class=\"s-note\">SHOT \u00b7 DESCENT OVER THE PASSAGE</span>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- ============ 5 \u00b7 BELONG (STAY) \u2014 inward ============ -->\n<section class=\"pillar belong\" id=\"belong\" data-cms=\"pillar\" data-pillar=\"stay\" data-world=\"whitsundays\">\n  <div class=\"wrap pillar-grid\">\n    <div class=\"scene-holder\">\n      <div class=\"scene-frame enter\" aria-hidden=\"true\">\n        <span class=\"s-note\">SHOT \u00b7 TERRACE, LIMESTONE, THE PASSAGE BEYOND</span>\n      </div>\n    </div>\n    <div>\n      <p class=\"eyebrow enter\">Belong</p>\n      <h2 class=\"display enter d1\">An island residence at the centre of it all.</h2>\n      <p class=\"lede enter d2\">Hamilton Island living \u2014 open architecture, limestone and timber, the water framed from every room. The residence is the point of return: where the world becomes personal.</p>\n      <div class=\"p-themes enter d3\">\n        <span>Private residences</span><span>Island living</span><span>Architecture</span><span>The point of return</span>\n      </div>\n      <a class=\"action enter d3\" href=\"/stay?dest=whitsundays&src=world-belong\">Continue into STAY <span class=\"mark\">\u2192</span></a>\n    </div>\n  </div>\n</section>\n\n<!-- ============ 6 \u00b7 EXPLORE (SEA) \u2014 horizontal ============ -->\n<section class=\"pillar explore\" id=\"explore\" data-cms=\"pillar\" data-pillar=\"sea\" data-world=\"whitsundays\">\n  <div class=\"wrap pillar-grid\">\n    <div>\n      <p class=\"eyebrow drift\">Explore</p>\n      <h2 class=\"display drift d1\">The passage, crossed at your own pace.</h2>\n      <p class=\"lede drift d2\">ALANI through the islands \u2014 Whitehaven at first light, the still anchorages of Hook, and the outer reef when the weather opens. The sea is how this world was always meant to be read.</p>\n      <div class=\"p-themes drift d3\">\n        <span>ALANI</span><span>Whitehaven</span><span>Outer reef</span><span>Private anchorages</span>\n      </div>\n      <a class=\"action drift d3\" href=\"/sea?dest=whitsundays&src=world-explore\">Continue into SEA <span class=\"mark\">\u2192</span></a>\n    </div>\n    <div class=\"scene-holder\">\n      <div class=\"scene-frame drift right d1\" aria-hidden=\"true\">\n        <span class=\"s-note\">SHOT \u00b7 THE PASSAGE, BEAM ON, MID MORNING</span>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- ============ 7 \u00b7 EXTRAORDINARY MOMENTS ============ -->\n<section class=\"dark moments\" id=\"moments\">\n  <div class=\"wrap\">\n    <p class=\"eyebrow rise\">Extraordinary moments</p>\n    <h2 class=\"display rise d1\">The days are made of these.</h2>\n    <p class=\"lede rise d2\">Experiences are woven into the journey, never bolted on. Each is arranged around where you are staying, sailing and arriving.</p>\n\n    <!-- Experiences render from `experience` via CMS-authored relationships -->\n    <div class=\"moment-flow rise d2\">\n      <a class=\"mstory\" href=\"/begin?dest=whitsundays&experience=private-chef&src=world-moments\" data-cms=\"experience\">\n        <span class=\"m-name\">Private chef</span>\n        <span class=\"m-line\">Dinner cooked where it was caught, served as the anchorage goes quiet.</span>\n        <span class=\"m-go\">Add to a journey</span>\n      </a>\n      <a class=\"mstory\" href=\"/begin?dest=whitsundays&experience=helicopter&src=world-moments\" data-cms=\"experience\">\n        <span class=\"m-name\">Helicopter</span>\n        <span class=\"m-line\">The reef from above \u2014 then down to a sandbar that disappears with the tide.</span>\n        <span class=\"m-go\">Add to a journey</span>\n      </a>\n      <a class=\"mstory\" href=\"/begin?dest=whitsundays&experience=wine&src=world-moments\" data-cms=\"experience\">\n        <span class=\"m-name\">Wine</span>\n        <span class=\"m-line\">A cellar chosen before you arrive, opened slowly across the week.</span>\n        <span class=\"m-go\">Add to a journey</span>\n      </a>\n      <a class=\"mstory\" href=\"/begin?dest=whitsundays&experience=reef&src=world-moments\" data-cms=\"experience\">\n        <span class=\"m-name\">Reef</span>\n        <span class=\"m-line\">Snorkelling the fringing coral at slack water, guided, unhurried.</span>\n        <span class=\"m-go\">Add to a journey</span>\n      </a>\n      <a class=\"mstory\" href=\"/begin?dest=whitsundays&experience=fishing&src=world-moments\" data-cms=\"experience\">\n        <span class=\"m-name\">Fishing</span>\n        <span class=\"m-line\">Dawn on the outer edges, lines out before the heat arrives.</span>\n        <span class=\"m-go\">Add to a journey</span>\n      </a>\n      <a class=\"mstory\" href=\"/begin?dest=whitsundays&experience=sunrise&src=world-moments\" data-cms=\"experience\">\n        <span class=\"m-name\">Sunrise</span>\n        <span class=\"m-line\">Coffee on deck as the passage turns from grey to green to gold.</span>\n        <span class=\"m-go\">Add to a journey</span>\n      </a>\n      <a class=\"mstory\" href=\"/begin?dest=whitsundays&experience=picnic&src=world-moments\" data-cms=\"experience\">\n        <span class=\"m-name\">Picnic</span>\n        <span class=\"m-line\">A table set on sand that will be underwater by evening.</span>\n        <span class=\"m-go\">Add to a journey</span>\n      </a>\n      <a class=\"mstory\" href=\"/begin?dest=whitsundays&experience=wellness&src=world-moments\" data-cms=\"experience\">\n        <span class=\"m-name\">Wellness</span>\n        <span class=\"m-line\">Morning practice on the foredeck; the horizon does the rest.</span>\n        <span class=\"m-go\">Add to a journey</span>\n      </a>\n      <a class=\"mstory\" href=\"/begin?dest=whitsundays&experience=photography&src=world-moments\" data-cms=\"experience\">\n        <span class=\"m-name\">Photography</span>\n        <span class=\"m-line\">The week documented quietly, so no one has to leave the moment to keep it.</span>\n        <span class=\"m-go\">Add to a journey</span>\n      </a>\n    </div>\n  </div>\n</section>\n\n<!-- ============ 8 \u00b7 THE JOURNAL ============ -->\n<section class=\"journal\" id=\"journal\">\n  <div class=\"wrap\">\n    <div class=\"journal-head\">\n      <p class=\"eyebrow rise\">The journal</p>\n      <h2 class=\"display rise d1\">Notes from this world.</h2>\n    </div>\n\n    <!-- Journal entries render from `journalEntry` filtered to this world -->\n    <div class=\"stories\">\n      <a class=\"story s1 enter\" href=\"/journal/quieter-side-of-whitehaven\" data-cms=\"journalEntry\">\n        <div class=\"frame\"><span class=\"sc\">SHOT \u00b7 SOUTHERN END, NO FOOTPRINTS</span></div>\n        <h3>The quieter side of Whitehaven</h3>\n        <p class=\"mono-note s-kind\">FIELD NOTES</p>\n      </a>\n      <a class=\"story s2 enter d1\" href=\"/journal/morning-on-hook-island\" data-cms=\"journalEntry\">\n        <div class=\"frame\"><span class=\"sc\">SHOT \u00b7 NARA INLET, 0600</span></div>\n        <h3>Morning on Hook Island</h3>\n        <p class=\"mono-note s-kind\">FIELD NOTES</p>\n      </a>\n      <a class=\"story s3 drift\" href=\"/journal/how-the-reef-changes-with-the-tide\" data-cms=\"journalEntry\">\n        <div class=\"frame\"><span class=\"sc\">SHOT \u00b7 CORAL EDGE, FALLING TIDE</span></div>\n        <h3>How the reef changes with the tide</h3>\n        <p class=\"mono-note s-kind\">ON THE WATER</p>\n      </a>\n      <a class=\"story s4 enter\" href=\"/journal/island-architecture\" data-cms=\"journalEntry\">\n        <div class=\"frame\"><span class=\"sc\">SHOT \u00b7 EAVES, LIMESTONE, SHADOW</span></div>\n        <h3>Island architecture</h3>\n        <p class=\"mono-note s-kind\">PLACES</p>\n      </a>\n      <a class=\"story s5 drift right\" href=\"/journal/travelling-by-private-yacht\" data-cms=\"journalEntry\">\n        <div class=\"frame\"><span class=\"sc\">SHOT \u00b7 WAKE ASTERN, LATE AFTERNOON</span></div>\n        <h3>Travelling by private yacht</h3>\n        <p class=\"mono-note s-kind\">THE JOURNEY</p>\n      </a>\n    </div>\n  </div>\n</section>\n\n<!-- ============ 9 \u00b7 ONE COMPLETE JOURNEY ============ -->\n<section class=\"complete\" id=\"journey\">\n  <div class=\"wrap\">\n    <div class=\"complete-head\">\n      <p class=\"eyebrow rise\">One journey, complete</p>\n      <h2 class=\"display rise d1\">Island Passage, plotted end to end.</h2>\n    </div>\n\n    <!-- Renders from `journey` + `journeyLeg` \u00b7 CMS-authored, one continuous course -->\n    <div class=\"voyage\" id=\"voyage\" data-cms=\"journey\" data-journey=\"island-passage\">\n      <div class=\"voyage-line\" aria-hidden=\"true\"><div class=\"plotted\" id=\"voyagePlotted\"></div></div>\n\n      <div class=\"leg\">\n        <div class=\"node\"></div>\n        <div><div class=\"l-kind\">Depart</div><div class=\"l-name\">Brisbane</div>\n        <p class=\"l-note\">The city recedes; the coordination begins.</p></div>\n      </div>\n      <div class=\"leg\">\n        <div class=\"node\"></div>\n        <div><div class=\"l-kind\">Air</div><div class=\"l-name\">Private aircraft</div>\n        <p class=\"l-note\">North over the coast, the islands appearing one by one.</p></div>\n      </div>\n      <div class=\"leg\">\n        <div class=\"node\"></div>\n        <div><div class=\"l-kind\">Stay</div><div class=\"l-name\">Hamilton Island residence</div>\n        <p class=\"l-note\">Bags disappear. The passage waits beyond the terrace.</p></div>\n      </div>\n      <div class=\"leg\">\n        <div class=\"node\"></div>\n        <div><div class=\"l-kind\">Sea</div><div class=\"l-name\">ALANI</div>\n        <p class=\"l-note\">Lines away mid-morning; the world becomes water.</p></div>\n      </div>\n      <div class=\"leg\">\n        <div class=\"node\"></div>\n        <div><div class=\"l-kind\">Experience</div><div class=\"l-name\">Whitehaven</div>\n        <p class=\"l-note\">Seven kilometres of silica, met before the day arrives.</p></div>\n      </div>\n      <div class=\"leg\">\n        <div class=\"node\"></div>\n        <div><div class=\"l-kind\">Experience</div><div class=\"l-name\">Private chef</div>\n        <p class=\"l-note\">Dinner aboard as the anchorage settles into evening.</p></div>\n      </div>\n      <div class=\"leg\">\n        <div class=\"node\"></div>\n        <div><div class=\"l-kind\">Air</div><div class=\"l-name\">Helicopter</div>\n        <p class=\"l-note\">The reef from above on the way back to the runway.</p></div>\n      </div>\n      <div class=\"leg\">\n        <div class=\"node\"></div>\n        <div><div class=\"l-kind\">Return</div><div class=\"l-name\">Home</div>\n        <p class=\"l-note\">The course complete \u2014 held as one movement throughout.</p></div>\n      </div>\n    </div>\n\n    <div class=\"voyage-actions rise\">\n      <a class=\"action\" href=\"/begin?journey=island-passage&src=world-journey\">Explore the journey <span class=\"mark\">\u2192</span></a>\n      <a class=\"action quiet\" href=\"/begin?journey=island-passage&shape=1&src=world-journey\">Shape this journey <span class=\"mark\">\u2192</span></a>\n    </div>\n  </div>\n</section>\n\n<!-- ============ 10 \u00b7 BEGIN \u2014 sunset, one button ============ -->\n<section class=\"begin\" id=\"begin\">\n  <div class=\"wrap\">\n    <h2 class=\"display rise\">Where will your journey begin?</h2>\n    <div class=\"rise d1\">\n      <a class=\"action solid\" href=\"/begin?dest=whitsundays&src=world-begin\">Begin a journey <span class=\"mark\">\u2192</span></a>\n    </div>\n  </div>\n</section>\n\n<!-- ============ FOOTER ============ -->\n<footer class=\"footer dark\">\n  <div class=\"wrap\">\n    <div class=\"footer-top\">\n      <div>\n        <div class=\"wordmark\">WAYPOINT &amp; Co.<span>THE WORLD</span></div>\n      </div>\n      <div>\n        <h4>The World</h4>\n        <ul>\n          <li><a href=\"/world/whitsundays\">The Whitsundays</a></li>\n          <li><a href=\"/world\">All worlds</a></li>\n        </ul>\n      </div>\n      <div>\n        <h4>Journey</h4>\n        <ul>\n          <li><a href=\"/air\">Air</a></li>\n          <li><a href=\"/sea\">Sea</a></li>\n          <li><a href=\"/stay\">Stay</a></li>\n          <li><a href=\"/journeys\">Journeys</a></li>\n        </ul>\n      </div>\n      <div>\n        <h4>Company</h4>\n        <ul>\n          <li><a href=\"/about\">About</a></li>\n          <li><a href=\"/contact\">Contact</a></li>\n          <li><a href=\"/terms\">Terms</a></li>\n          <li><a href=\"/privacy\">Privacy</a></li>\n        </ul>\n      </div>\n    </div>\n    <div class=\"footer-bottom\">\n      <span class=\"mono-note\">THE WORLD \u00b7 01 \u00b7 THE WHITSUNDAYS \u00b7 20\u00b0S 149\u00b0E</span>\n      <span class=\"mono-note\">\u00a9 WAYPOINT &amp; CO.</span>\n    </div>\n  </div>\n</footer>";
const JS = "(function(){\n  const reduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;\n\n  /* ---- nav ---- */\n  const nav = document.getElementById('nav');\n  const onScrollNav = () => nav.classList.toggle('scrolled', window.scrollY > 40);\n  onScrollNav();\n  window.addEventListener('scroll', onScrollNav, { passive: true });\n\n  /* ---- the three movement languages ---- */\n  const revealEls = document.querySelectorAll('.rise, .drift, .enter, .wpt, .leg');\n  if ('IntersectionObserver' in window && !reduced){\n    const io = new IntersectionObserver((entries) => {\n      entries.forEach(e => {\n        if (e.isIntersecting){ e.target.classList.add('in'); io.unobserve(e.target); }\n      });\n    }, { threshold: 0.15, rootMargin: '0px 0px -6% 0px' });\n    revealEls.forEach(el => io.observe(el));\n  } else {\n    revealEls.forEach(el => el.classList.add('in'));\n  }\n\n  /* ---- plotted lines draw with scroll ---- */\n  function scrollDraw(containerId, fillId){\n    const box = document.getElementById(containerId);\n    const fill = document.getElementById(fillId);\n    if (!box || !fill || reduced) return;\n    const draw = () => {\n      const r = box.getBoundingClientRect();\n      const vh = window.innerHeight;\n      const start = vh * 0.82;\n      const total = r.height + (start - vh * 0.3);\n      const travelled = Math.min(Math.max(start - r.top, 0), total);\n      fill.style.height = (travelled / total * 100).toFixed(2) + '%';\n    };\n    draw();\n    window.addEventListener('scroll', draw, { passive: true });\n    window.addEventListener('resize', draw);\n  }\n  scrollDraw('chart', 'chartPlotted');\n  scrollDraw('voyage', 'voyagePlotted');\n})();\n\n/* WJ active-state (v2.0.1) */\n(function(){\n  var marks = document.querySelectorAll('.wj-mark');\n  var cur = document.querySelector('.wj-progress .cur');\n  if (!marks.length || !('IntersectionObserver' in window)) { if (marks[0]) marks[0].classList.add('on'); return; }\n  var io = new IntersectionObserver(function(es){\n    es.forEach(function(en){\n      if (en.isIntersecting) {\n        marks.forEach(function(m){ m.classList.toggle('on', m.getAttribute('data-wj') === en.target.id); });\n        if (cur) cur.textContent = '0' + (Array.prototype.findIndex.call(marks, function(m){ return m.getAttribute('data-wj') === en.target.id; }) + 1);\n      }\n    });\n  }, { rootMargin: '-38% 0px -52% 0px' });\n  document.querySelectorAll('.wj-stage').forEach(function(s){ io.observe(s); });\n  if (marks[0]) marks[0].classList.add('on');\n})();";

export default function WhitsundaysPage() {
  useEffect(() => {
    try { new Function(JS)(); } catch (e) { console.error("page script:", e); }
  }, []);
  return (
    <>
      <style dangerouslySetInnerHTML={{ __html: CSS }} />
      <div dangerouslySetInnerHTML={{ __html: HTML }} />
    </>
  );
}
